import base64
import zlib
import requests
from urllib.parse import quote_plus
from xml.sax.saxutils import escape

def build_saml_request(destination_url, user_info):
    saml_request_template = '''
    <samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" 
                        ID="_{}" 
                        Version="2.0" 
                        IssueInstant="{}" 
                        Destination="{}" 
                        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" 
                        AssertionConsumerServiceURL="{}">
        <saml:Issuer>{}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified" AllowCreate="true"/>
    </samlp:AuthnRequest>
    '''
    
    # Securely escape user-provided values
    user_id = escape(user_info.get('user_id', ''))
    issue_instant = escape(user_info.get('issue_instant', ''))
    acs_url = escape(user_info.get('acs_url', ''))
    issuer = escape(user_info.get('issuer', ''))

    saml_request = saml_request_template.format(user_id, issue_instant, escape(destination_url), acs_url, issuer)
    return saml_request

def encode_saml_request(saml_request):
    deflate_data = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    base64_encoded = base64.b64encode(deflate_data)
    return quote_plus(base64_encoded)

def post_saml_request(destination_url, saml_request):
    encoded_request = encode_saml_request(saml_request)
    response = requests.post(destination_url, data={'SAMLRequest': encoded_request})
    return response

